args.sparql:
SELECT ?instanceLabel WHERE {
  wd:Q2351672 wdt:P31 ?instance .
  ?instance rdfs:label ?instanceInitializer .
  FILTER(LANG(?instanceInitializer) = 'en')
}

SELECT ?instance ?instanceLabel WHERE {
  wd:Q2351672 wdt:P31 ?instance .
  ?instance rdfs:label ?instanceLabel .
  FILTER(LANG(?instanceLabel) = 'en')
}

SELECT ?editor ?editorLabel WHERE {
  wd:Q2351672 wdt:P1040 ?editor .
  ?editor rdfs:label ?editorLabel .
  FILTER(LANG(?editorLabel) = 'en')
}

SELECT ?editorLabel WHERE {
  wd:Q2351672 wdt:P1040 ?editor .
  ?editor rdfs:label ?editorLabel .
  FILTER(LANG(?editorLabel) = 'en')
}
